// ============================================================
// CONSTRUIR COMANDO desde la plantilla de MongoDB + params del usuario
// ============================================================
// MongoDB devuelve la plantilla con command_base y params por defecto.
// El webhook envia los params del usuario que sobreescriben los defaults.
// Este nodo fusiona ambos y reemplaza los {{placeholders}}.
// ============================================================

const mongoResult = $input.first().json;
const webhookData = $('Webhook').first().json;
const body = webhookData.body || webhookData;

const taskName = body.task_name || 'unknown';
const userParams = body.params || {};
const ts = Date.now();

// Si MongoDB devolvio plantilla, usarla; si no, fallback
let commandBase = '';
let templateParams = {};
let postNotify = '';
let mitreId = 'N/A';
let severity = 'medium';

if (mongoResult && mongoResult.command_base) {
  commandBase = mongoResult.command_base;
  templateParams = mongoResult.params || {};
  postNotify = mongoResult.post_attack_notify || '';
  mitreId = mongoResult.mitre_id || 'N/A';
  severity = mongoResult.severity || 'medium';
} else {
  // FALLBACK: si no hay plantilla en MongoDB para este ataque
  commandBase = 'echo "Ataque no encontrado en MongoDB: ' + taskName + '"';
}

// Fusionar params: defaults de MongoDB + overrides del usuario
const mergedParams = Object.assign({}, templateParams, userParams);
mergedParams.timestamp = String(ts);

// Reemplazar todos los {{placeholder}} en el comando
let command = commandBase;
for (const [key, value] of Object.entries(mergedParams)) {
  const regex = new RegExp('\\{\\{' + key + '\\}\\}', 'g');
  command = command.replace(regex, String(value));
}

// Construir el post_attack_notify (logger para Wazuh)
let loggerCmd = postNotify;
for (const [key, value] of Object.entries(mergedParams)) {
  const regex = new RegExp('\\{\\{' + key + '\\}\\}', 'g');
  loggerCmd = loggerCmd.replace(regex, String(value));
}

// Encadenar: comando del ataque + logger para Wazuh
const fullCommand = loggerCmd
  ? command + '; ' + loggerCmd
  : command;

return [{
  json: {
    command: fullCommand,
    task_name: taskName,
    params: mergedParams,
    mitre_id: mitreId,
    severity: severity,
    timestamp: ts,
    started_at: new Date().toISOString()
  }
}];

// Post-procesado: recoger output y preparar datos para informe PDF
const ssh = $input.first().json;
const prev = $('Code in JavaScript').first().json;
const stdout = ssh.stdout || '';
const stderr = ssh.stderr || '';
const exitCode = ssh.exitCode || 0;
const durationSec = Math.round((Date.now() - new Date(prev.started_at).getTime()) / 1000);

return [{
  json: {
    task_name: prev.task_name,
    params: prev.params,
    mitre_id: prev.mitre_id,
    severity: prev.severity,
    timestamp: prev.timestamp,
    started_at: prev.started_at,
    finished_at: new Date().toISOString(),
    duration_seconds: durationSec,
    output: stdout,
    stderr: stderr,
    exit_code: exitCode,
    success: exitCode === 0,
    xml_output: stdout.includes('<?xml') ? stdout : '',
    target: prev.params.target || prev.params.bssid || prev.params.interface || 'N/A',
    scan_target: prev.params.target || 'N/A'
  }
}];
